import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:5000/api',
  timeout: 30000,
  headers: { 'Content-Type': 'application/json' },
});

// Request interceptor — attach token
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('accessToken');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
  },
  (error) => Promise.reject(error)
);

// Response interceptor — handle token refresh
api.interceptors.response.use(
  (response) => response,
  async (error) => {
    const original = error.config;
    if (error.response?.status === 401 && !original._retry) {
      original._retry = true;
      const refreshToken = localStorage.getItem('refreshToken');
      if (refreshToken) {
        try {
          const { data } = await axios.post(`${api.defaults.baseURL}/auth/refresh`, { refreshToken });
          localStorage.setItem('accessToken', data.data.accessToken);
          localStorage.setItem('refreshToken', data.data.refreshToken);
          original.headers.Authorization = `Bearer ${data.data.accessToken}`;
          return api(original);
        } catch {
          localStorage.removeItem('accessToken');
          localStorage.removeItem('refreshToken');
          window.location.href = '/login';
        }
      }
    }
    return Promise.reject(error);
  }
);

// API service methods
export const studentAPI = {
  getAll: (params) => api.get('/students', { params }),
  getOne: (id) => api.get(`/students/${id}`),
  create: (data) => api.post('/students', data),
  update: (id, data) => api.put(`/students/${id}`, data),
  delete: (id) => api.delete(`/students/${id}`),
  promote: (id, data) => api.post(`/students/${id}/promote`, data),
};

export const feeAPI = {
  getStructure: (params) => api.get('/fees/structure', { params }),
  getStudentFees: (studentId) => api.get(`/fees/student/${studentId}`),
  collect: (data) => api.post('/fees/collect', data),
  getCollection: (params) => api.get('/fees/collection-report', { params }),
  getPending: (params) => api.get('/fees/pending', { params }),
};

export const attendanceAPI = {
  mark: (data) => api.post('/attendance/student/mark', data),
  getClass: (params) => api.get('/attendance/student/class', { params }),
  getMonthly: (studentId, params) => api.get(`/attendance/student/${studentId}/monthly`, { params }),
  getReport: (params) => api.get('/attendance/report', { params }),
};

export const dashboardAPI = {
  get: () => api.get('/dashboard'),
};

export const noticeAPI = {
  getAll: (params) => api.get('/notices', { params }),
  create: (data) => api.post('/notices', data),
};

export const enquiryAPI = {
  getAll: (params) => api.get('/enquiries', { params }),
  create: (data) => api.post('/enquiries', data),
  update: (id, data) => api.put(`/enquiries/${id}`, data),
};

export const employeeAPI = {
  getAll: (params) => api.get('/employees', { params }),
  create: (data) => api.post('/employees', data),
  update: (id, data) => api.put(`/employees/${id}`, data),
};

export const reportAPI = {
  getAttendance: (params) => api.get('/reports/attendance', { params }),
  getFee: (params) => api.get('/reports/fee', { params }),
  getExam: (params) => api.get('/reports/exam', { params }),
};

export default api;
